def combine_cfs(cf_a: float, cf_b: float) -> float:
    """Combine two certainty factors using MYCIN's combination rules."""
    if cf_a >= 0 and cf_b >= 0:
        return cf_a + cf_b * (1 - cf_a)
    elif cf_a < 0 and cf_b < 0:
        return cf_a + cf_b * (1 + cf_a)
    else:
        denom = 1 - min(abs(cf_a), abs(cf_b))
        return (cf_a + cf_b) / denom if denom != 0 else 0.0


@dataclass
class CFRule:
    name: str
    conditions: list[str]       # required facts
    conclusion: str
    cf: float                   # certainty this rule adds when all conditions hold


class MYCINStyleAgent:
    def __init__(self, rules: list[CFRule]):
        self.rules = rules

    def run(self, facts: dict[str, float]) -> dict[str, float]:
        """
        facts: {fact_name: certainty_factor}
        Returns updated dict with derived conclusions and their CFs.
        """
        working = dict(facts)
        changed = True
        while changed:
            changed = False
            for rule in self.rules:
                # Use minimum CF of conditions (weakest link)
                if not all(working.get(c, 0) > 0.2 for c in rule.conditions):
                    continue
                min_cf = min(working.get(c, 0) for c in rule.conditions)
                derived_cf = min_cf * rule.cf  # scale rule CF by evidence strength
                old = working.get(rule.conclusion, 0)
                new = combine_cfs(old, derived_cf)
                if abs(new - old) > 0.001:
                    working[rule.conclusion] = new
                    print(f"  {rule.name}: CF={new:.2f}")
                    changed = True
        return working


rules = [
    CFRule("fever+cough→flu",  ["fever", "cough"],        "suspect_flu",          cf=0.7),
    CFRule("flu+duration→Rx",  ["suspect_flu", "long_duration"], "recommend_antivirals", cf=0.8),
]

observations = {"fever": 0.9, "cough": 0.6, "long_duration": 0.95}
agent = MYCINStyleAgent(rules)
result = agent.run(observations)

print("\nFinal certainty factors:")
for fact, cf in sorted(result.items()):
    if cf > 0.2:
        print(f"  {fact}: {cf:.2f}")

import unittest

class TestMedicalRules(unittest.TestCase):

    def setUp(self):
        self.agent = ForwardChainingAgent(rules)   # rules from the first example

    def test_flu_diagnosis_fires_on_fever_and_cough(self):
        result = self.agent.run({"fever", "cough"})
        self.assertIn("suspect_flu", result)

    def test_flu_diagnosis_does_not_fire_without_cough(self):
        result = self.agent.run({"fever"})
        self.assertNotIn("suspect_flu", result)

    def test_antivirals_require_long_duration(self):
        result_short = self.agent.run({"fever", "cough"})
        self.assertNotIn("recommend_antivirals", result_short)

        result_long = self.agent.run({"fever", "cough", "duration_gt_3d"})
        self.assertIn("recommend_antivirals", result_long)

    def test_measles_fires_on_fever_and_rash(self):
        result = self.agent.run({"fever", "rash"})
        self.assertIn("suspect_measles", result)
        self.assertNotIn("suspect_flu", result)  # no cough

    def test_no_infinite_loop(self):
        # Running multiple times on the same facts must terminate
        for _ in range(10):
            self.agent.run({"fever", "cough", "duration_gt_3d"})

if __name__ == "__main__":
    unittest.main()
